python - <<'PY' 2>/dev/null || echo "trl not importable in this env"
import dataclasses, trl
print("trl version:", getattr(trl, "__version__", "?"))
fields = {f.name for f in dataclasses.fields(trl.ScriptArguments)}
for n in ["dataset_name","dataset_config","dataset_train_split","dataset_test_split","dataset_num_proc","eos_token","use_liger_kernel"]:
    print(n, "->", n in fields or "(not in ScriptArguments base)")
# Check SFTConfig-specific additions vs TrainingArguments
from trl import SFTConfig
sft_fields = {f.name for f in dataclasses.fields(SFTConfig)}
for n in ["max_length","packing","max_seq_length","use_liger_kernel","chat_template","system_prompt"]:
    print("SFTConfig has", n, "->", n in sft_fields)
from trl import GRPOConfig
grpo_fields = {f.name for f in dataclasses.fields(GRPOConfig)}
for n in ["use_vllm","num_generations","max_prompt_length","max_completion_length","reward_funcs","reward_weights","log_completions"]:
    print("GRPOConfig has", n, "->", n in grpo_fields)
from trl import ModelConfig
mc_fields = {f.name for f in dataclasses.fields(ModelConfig)}
for n in ["model_name_or_path","model_revision","torch_dtype","attn_implementation"]:
    print("ModelConfig has", n, "->", n in mc_fields)
